        const __m256d t0r = _mm256_fnmadd_pd(cK3,_mm256_add_pd(s1r,s2r),x0r), t0i = _mm256_fnmadd_pd(cK3,_mm256_add_pd(s1i,s2i),x0i);
        const __m256d t1r = _mm256_mul_pd(cK0,_mm256_sub_pd(s1r,s2r)), t1i = _mm256_mul_pd(cK0,_mm256_sub_pd(s1i,s2i));
